import React, { useState, useCallback, useEffect, useRef } from 'react';
import { StandObject, Boundary, OBJECT_DEFAULTS } from '../types';

interface DraggableItemProps {
  object: StandObject;
  scale: number;
  boundary: Boundary;
  isSelected: boolean;
  hasError: boolean;
  onSelect: (e: React.MouseEvent) => void;
  onUpdate: (updates: Partial<StandObject>, finalUpdate?: boolean) => void;
}

const DraggableItem: React.FC<DraggableItemProps> = ({ object, scale, isSelected, hasError, onSelect, onUpdate }) => {
  const [dragging, setDragging] = useState(false);
  const [resizing, setResizing] = useState(false);
  const [rotating, setRotating] = useState(false);
  const [startPos, setStartPos] = useState({ x: 0, y: 0 });
  const containerRef = useRef<HTMLDivElement>(null);

  const handlePointerDown = (e: React.PointerEvent) => {
    e.stopPropagation();
    onSelect(e as any);
    setDragging(true);
    setStartPos({ x: e.clientX - object.x * scale, y: e.clientY - object.y * scale });
    (e.target as HTMLElement).setPointerCapture(e.pointerId);
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (dragging) {
      const newX = (e.clientX - startPos.x) / scale;
      const newY = (e.clientY - startPos.y) / scale;
      onUpdate({ x: newX, y: newY });
    } else if (resizing) {
      const rect = (e.currentTarget.parentElement as HTMLElement).getBoundingClientRect();
      const newWidth = (e.clientX - (object.x * scale + rect.left)) / scale;
      const newLength = (e.clientY - (object.y * scale + rect.top)) / scale;
      onUpdate({ 
        width: Math.max(0.1, newWidth), 
        length: Math.max(0.1, newLength) 
      });
    } else if (rotating) {
      const rect = containerRef.current?.getBoundingClientRect();
      if (!rect) return;
      const centerX = rect.left + rect.width / 2;
      const centerY = rect.top + rect.height / 2;
      const angle = Math.atan2(e.clientY - centerY, e.clientX - centerX) * (180 / Math.PI);
      onUpdate({ rotation: (angle + 90) % 360 });
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    if (dragging || resizing || rotating) {
      onUpdate({}, true); // Trigger history save
    }
    setDragging(false);
    setResizing(false);
    setRotating(false);
    (e.target as HTMLElement).releasePointerCapture(e.pointerId);
  };

  const handleResizeStart = (e: React.PointerEvent) => {
    e.stopPropagation();
    setResizing(true);
    (e.target as HTMLElement).setPointerCapture(e.pointerId);
  };

  const handleRotateStart = (e: React.PointerEvent) => {
    e.stopPropagation();
    setRotating(true);
    (e.target as HTMLElement).setPointerCapture(e.pointerId);
  };

  const handleClick = (e: React.MouseEvent) => {
    // CRITICAL: Stop propagation of the click event so the Canvas background 
    // does not receive a click and clear the selection.
    e.stopPropagation();
  };

  const isSafetyOrAccess = object.type === 'Fire Extinguisher' || object.type === 'Entry/Exit Point';

  return (
    <div
      ref={containerRef}
      className={`absolute transition-shadow touch-none flex items-center justify-center text-center select-none shadow-sm ${isSelected ? 'z-50 ring-2 ring-emerald-500' : 'z-10'}`}
      style={{
        left: `${object.x * scale}px`,
        top: `${object.y * scale}px`,
        width: `${object.width * scale}px`,
        height: `${object.length * scale}px`,
        backgroundColor: object.color,
        border: hasError ? '2px solid #ef4444' : 'none',
        opacity: OBJECT_DEFAULTS[object.type].transparent ? 0.4 : 1,
        transform: `rotate(${object.rotation}deg)`,
      }}
      onPointerDown={handlePointerDown}
      onPointerMove={handlePointerMove}
      onPointerUp={handlePointerUp}
      onClick={handleClick}
    >
      <span className={`text-[8px] font-bold p-1 leading-tight break-words pointer-events-none ${object.color === 'rgba(255, 255, 255, 1)' ? 'text-slate-800' : 'text-white'}`}>
        {object.type === 'Fire Extinguisher' ? 'EXT' : object.type === 'Entry/Exit Point' ? 'IN/OUT' : object.type}
      </span>

      {hasError && !OBJECT_DEFAULTS[object.type].ignoreCollision && (
        <div className="absolute -top-3 -right-3 bg-red-500 text-white rounded-full w-5 h-5 flex items-center justify-center text-[10px] font-bold shadow-lg animate-bounce pointer-events-none">
          !
        </div>
      )}

      {isSelected && (
        <>
          {/* Rotate handle */}
          <div
            className="absolute -top-8 left-1/2 -translate-x-1/2 w-6 h-6 bg-white border-2 border-emerald-500 rounded-full cursor-alias flex items-center justify-center shadow-lg"
            onPointerDown={handleRotateStart}
          >
            <svg className="w-4 h-4 text-emerald-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
            </svg>
          </div>

          {/* Resize handle */}
          <div
            className="absolute bottom-0 right-0 w-4 h-4 bg-emerald-500 cursor-nwse-resize rounded-tl-sm flex items-center justify-center"
            onPointerDown={handleResizeStart}
          >
            <div className="w-1.5 h-1.5 border-r-2 border-b-2 border-white" />
          </div>

          {/* Measurement overlays */}
          <div className="absolute -bottom-6 left-1/2 -translate-x-1/2 whitespace-nowrap text-[10px] font-mono text-emerald-600 font-bold bg-white/80 px-1 rounded shadow-sm border border-emerald-100">
            {object.width.toFixed(1)}m × {object.length.toFixed(1)}m @ {Math.round(object.rotation)}°
          </div>
        </>
      )}
    </div>
  );
};

export default DraggableItem;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { VendorInfo, StandObject, ObjectType, OBJECT_DEFAULTS, Boundary } from '../types';
import Sidebar from './Sidebar';
import Canvas from './Canvas';
import Controls from './Controls';
import { toPng } from 'https://esm.sh/html-to-image@1.11.11';

interface DesignerProps {
  vendor: VendorInfo;
  onLogout: () => void;
}

const Designer: React.FC<DesignerProps> = ({ vendor, onLogout }) => {
  const [boundary, setBoundary] = useState<Boundary>({ width: 10, length: 8 });
  const [objects, setObjects] = useState<StandObject[]>([]);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [isBoundarySet, setIsBoundarySet] = useState(false);
  const [isExporting, setIsExporting] = useState(false);

  const [history, setHistory] = useState<StandObject[][]>([]);
  const [redoStack, setRedoStack] = useState<StandObject[][]>([]);
  const [scale, setScale] = useState(40);

  const saveToHistory = useCallback((currentObjects: StandObject[]) => {
    setHistory(prev => [...prev, currentObjects]);
    setRedoStack([]);
  }, []);

  const addObject = useCallback((type: ObjectType) => {
    saveToHistory(objects);
    const defaults = OBJECT_DEFAULTS[type];
    const newObj: StandObject = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      x: boundary.width / 2 - defaults.width / 2,
      y: type === 'Queue Barrier' ? boundary.length + 1 : boundary.length / 2 - defaults.length / 2,
      width: defaults.width,
      length: defaults.length,
      rotation: 0,
      color: defaults.color,
    };
    setObjects(prev => [...prev, newObj]);
    setSelectedId(newObj.id);
  }, [boundary, objects, saveToHistory]);

  const updateObject = (id: string, updates: Partial<StandObject>, finalUpdate = false) => {
    if (finalUpdate) {
      saveToHistory(objects);
    }
    setObjects(prev => prev.map(obj => obj.id === id ? { ...obj, ...updates } : obj));
  };

  const removeObject = (id: string) => {
    saveToHistory(objects);
    setObjects(prev => prev.filter(obj => obj.id !== id));
    if (selectedId === id) setSelectedId(null);
  };

  const undo = useCallback(() => {
    if (history.length > 0) {
      const previous = history[history.length - 1];
      const newHistory = history.slice(0, history.length - 1);
      setRedoStack(prev => [objects, ...prev]);
      setObjects(previous);
      setHistory(newHistory);
    }
  }, [history, objects]);

  const redo = useCallback(() => {
    if (redoStack.length > 0) {
      const next = redoStack[0];
      const newRedoStack = redoStack.slice(1);
      setHistory(prev => [...prev, objects]);
      setObjects(next);
      setRedoStack(newRedoStack);
    }
  }, [redoStack, objects]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.ctrlKey || e.metaKey) && e.key === 'z') {
        if (e.shiftKey) redo();
        else undo();
      } else if ((e.ctrlKey || e.metaKey) && e.key === 'y') {
        redo();
      } else if (e.key === 'Delete' || e.key === 'Backspace') {
        if (selectedId && !['INPUT', 'TEXTAREA'].includes(document.activeElement?.tagName || '')) {
          removeObject(selectedId);
        }
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [undo, redo, selectedId]);

  const resetDesigner = () => {
    if (confirm("Clear your entire sketch?")) {
      saveToHistory(objects);
      setObjects([]);
      setSelectedId(null);
    }
  };

  const exportDesign = async () => {
    const node = document.getElementById('full-site-canvas');
    if (!node) return;

    setIsExporting(true);
    setSelectedId(null); // Clear selection for clean export

    // Brief delay to allow React state to clear the selection highlight
    setTimeout(async () => {
      try {
        const dataUrl = await toPng(node, {
          quality: 1,
          pixelRatio: 3, // Best quality resolution (high DPI)
          backgroundColor: '#f1f5f9', // Light slate background matches app
          style: {
            padding: '40px',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center'
          }
        });

        const link = document.createElement('a');
        link.download = `StandPlan-${vendor.traderName.replace(/\s+/g, '-')}.png`;
        link.href = dataUrl;
        link.click();
      } catch (err) {
        console.error('Export failed:', err);
        alert('Export failed. Please try again or use the print function.');
      } finally {
        setIsExporting(false);
      }
    }, 150);
  };

  if (!isBoundarySet) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-50">
        <div className="bg-white p-10 rounded-2xl shadow-xl max-w-lg w-full border border-slate-200">
          <h2 className="text-2xl font-bold mb-6 text-slate-800">Set Your Stand Dimensions</h2>
          <p className="text-slate-500 mb-8">Enter the outer boundaries of your pitch in meters.</p>
          <div className="grid grid-cols-2 gap-6 mb-8">
            <div>
              <label className="block text-sm font-semibold text-slate-600 mb-2">Width (m)</label>
              <input
                type="number"
                className="w-full p-4 border rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none"
                value={boundary.width}
                onChange={(e) => setBoundary({ ...boundary, width: parseFloat(e.target.value) || 0 })}
              />
            </div>
            <div>
              <label className="block text-sm font-semibold text-slate-600 mb-2">Length (m)</label>
              <input
                type="number"
                className="w-full p-4 border rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none"
                value={boundary.length}
                onChange={(e) => setBoundary({ ...boundary, length: parseFloat(e.target.value) || 0 })}
              />
            </div>
          </div>
          <button
            onClick={() => setIsBoundarySet(true)}
            className="w-full bg-emerald-600 text-white font-bold py-4 rounded-xl hover:bg-emerald-700 transition shadow-lg"
          >
            Open Workspace
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-screen overflow-hidden bg-slate-100 print:h-auto print:overflow-visible">
      <Sidebar onAddObject={addObject} />

      <main className="flex-1 flex flex-col min-w-0 relative print:bg-white print:p-0">
        <header className="bg-white border-b px-6 py-4 flex items-center justify-between shadow-sm z-30 print:hidden">
          <div className="flex items-center space-x-4">
            <h1 className="text-xl font-bold text-slate-800 truncate max-w-xs">{vendor.traderName}</h1>
            <span className="text-slate-400">|</span>
            <span className="text-sm text-slate-500 font-mono">{vendor.vendorId}</span>
          </div>
          <div className="flex items-center space-x-2">
            <button 
              onClick={undo}
              disabled={history.length === 0}
              className={`p-2 rounded-lg transition ${history.length === 0 ? 'text-slate-200' : 'text-slate-600 hover:bg-slate-100 hover:text-emerald-600'}`}
              title="Undo (Ctrl+Z)"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 10h10a8 8 0 018 8v2M3 10l6 6m-6-6l6-6" /></svg>
            </button>
            <button 
              onClick={redo}
              disabled={redoStack.length === 0}
              className={`p-2 rounded-lg transition ${redoStack.length === 0 ? 'text-slate-200' : 'text-slate-600 hover:bg-slate-100 hover:text-emerald-600'}`}
              title="Redo (Ctrl+Y)"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 10h-10a8 8 0 00-8 8v2m18-8l-6 6m6-6l-6-6" /></svg>
            </button>
            <span className="text-slate-200 mx-2">|</span>
            <button 
              onClick={exportDesign}
              disabled={isExporting}
              className={`px-4 py-2 text-white text-sm font-bold rounded-lg transition flex items-center shadow-sm ${isExporting ? 'bg-slate-400 cursor-not-allowed' : 'bg-slate-800 hover:bg-slate-900'}`}
            >
              <svg className="w-4 h-4 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
              </svg>
              {isExporting ? 'Exporting...' : 'Export (PNG)'}
            </button>
            <span className="text-slate-200 mx-2">|</span>
             <button 
              onClick={resetDesigner}
              className="px-4 py-2 text-sm font-medium text-slate-600 hover:text-red-600 transition"
            >
              Clear
            </button>
            <button 
              onClick={onLogout}
              className="px-4 py-2 text-sm font-medium text-slate-600 hover:text-slate-900 transition"
            >
              Logout
            </button>
          </div>
        </header>

        <div className="flex-1 relative overflow-auto p-12 flex justify-center items-center canvas-container print:p-0 print:overflow-visible">
          <Canvas 
            boundary={boundary} 
            objects={objects} 
            selectedId={selectedId}
            scale={scale}
            onSelect={setSelectedId}
            onUpdate={updateObject}
          />
        </div>

        <Controls 
          selectedObject={objects.find(o => o.id === selectedId) || null}
          onUpdate={updateObject}
          onRemove={removeObject}
          onClose={() => setSelectedId(null)}
        />
      </main>
    </div>
  );
};

export default Designer;

import React, { useState, useCallback, useEffect, useRef } from 'react';
import { StandObject, Boundary, OBJECT_DEFAULTS } from '../types';

interface DraggableItemProps {
  object: StandObject;
  scale: number;
  boundary: Boundary;
  isSelected: boolean;
  hasError: boolean;
  onSelect: (e: React.MouseEvent) => void;
  onUpdate: (updates: Partial<StandObject>, finalUpdate?: boolean) => void;
}

const DraggableItem: React.FC<DraggableItemProps> = ({ object, scale, isSelected, hasError, onSelect, onUpdate }) => {
  const [dragging, setDragging] = useState(false);
  const [resizing, setResizing] = useState(false);
  const [rotating, setRotating] = useState(false);
  const [startPos, setStartPos] = useState({ x: 0, y: 0 });
  const containerRef = useRef<HTMLDivElement>(null);

  const handlePointerDown = (e: React.PointerEvent) => {
    e.stopPropagation();
    onSelect(e as any);
    setDragging(true);
    setStartPos({ x: e.clientX - object.x * scale, y: e.clientY - object.y * scale });
    (e.target as HTMLElement).setPointerCapture(e.pointerId);
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (dragging) {
      const newX = (e.clientX - startPos.x) / scale;
      const newY = (e.clientY - startPos.y) / scale;
      onUpdate({ x: newX, y: newY });
    } else if (resizing) {
      const rect = (e.currentTarget.parentElement as HTMLElement).getBoundingClientRect();
      const newWidth = (e.clientX - (object.x * scale + rect.left)) / scale;
      const newLength = (e.clientY - (object.y * scale + rect.top)) / scale;
      onUpdate({ 
        width: Math.max(0.1, newWidth), 
        length: Math.max(0.1, newLength) 
      });
    } else if (rotating) {
      const rect = containerRef.current?.getBoundingClientRect();
      if (!rect) return;
      const centerX = rect.left + rect.width / 2;
      const centerY = rect.top + rect.height / 2;
      const angle = Math.atan2(e.clientY - centerY, e.clientX - centerX) * (180 / Math.PI);
      onUpdate({ rotation: (angle + 90) % 360 });
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    if (dragging || resizing || rotating) {
      onUpdate({}, true); // Trigger history save
    }
    setDragging(false);
    setResizing(false);
    setRotating(false);
    (e.target as HTMLElement).releasePointerCapture(e.pointerId);
  };

  const handleResizeStart = (e: React.PointerEvent) => {
    e.stopPropagation();
    setResizing(true);
    (e.target as HTMLElement).setPointerCapture(e.pointerId);
  };

  const handleRotateStart = (e: React.PointerEvent) => {
    e.stopPropagation();
    setRotating(true);
    (e.target as HTMLElement).setPointerCapture(e.pointerId);
  };

  const handleClick = (e: React.MouseEvent) => {
    // Prevent deselecting when clicking or finishing a drag
    e.stopPropagation();
  };

  // Helper to determine text color based on object fill
  const getTextColorClass = () => {
    const darkFills = [
      'rgba(31, 41, 55, 1)', // Smoker
      'rgba(30, 41, 59, 1)', // Manager
      'rgba(31, 41, 55, 1)',
      'rgba(153, 27, 27, 1)', // Other (Hot)
      'rgba(185, 28, 28, 1)', // Asado
    ];

    if (darkFills.includes(object.color)) {
      return 'text-slate-200'; // Light grey for dark fill
    }
    return 'text-black'; // Black for everything else
  };

  return (
    <div
      ref={containerRef}
      className={`absolute transition-shadow touch-none flex items-center justify-center text-center select-none shadow-sm ${isSelected ? 'z-50 ring-2 ring-emerald-500' : 'z-10'}`}
      style={{
        left: `${object.x * scale}px`,
        top: `${object.y * scale}px`,
        width: `${object.width * scale}px`,
        height: `${object.length * scale}px`,
        backgroundColor: object.color,
        border: hasError ? '2px solid #ef4444' : 'none',
        opacity: OBJECT_DEFAULTS[object.type].transparent ? 0.4 : 1,
        transform: `rotate(${object.rotation}deg)`,
      }}
      onPointerDown={handlePointerDown}
      onPointerMove={handlePointerMove}
      onPointerUp={handlePointerUp}
      onClick={handleClick}
    >
      <span className={`text-[9px] font-bold p-1 leading-tight break-words pointer-events-none ${getTextColorClass()}`}>
        {object.type === 'Fire Extinguisher' ? 'EXT' : object.type === 'Entry/Exit Point' ? 'IN/OUT' : object.type}
      </span>

      {hasError && !OBJECT_DEFAULTS[object.type].ignoreCollision && (
        <div className="absolute -top-3 -right-3 bg-red-500 text-white rounded-full w-5 h-5 flex items-center justify-center text-[10px] font-bold shadow-lg animate-bounce pointer-events-none">
          !
        </div>
      )}

      {isSelected && (
        <>
          <div
            className="absolute -top-8 left-1/2 -translate-x-1/2 w-6 h-6 bg-white border-2 border-emerald-500 rounded-full cursor-alias flex items-center justify-center shadow-lg"
            onPointerDown={handleRotateStart}
          >
            <svg className="w-4 h-4 text-emerald-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
            </svg>
          </div>

          <div
            className="absolute bottom-0 right-0 w-4 h-4 bg-emerald-500 cursor-nwse-resize rounded-tl-sm flex items-center justify-center"
            onPointerDown={handleResizeStart}
          >
            <div className="w-1.5 h-1.5 border-r-2 border-b-2 border-white" />
          </div>

          <div className="absolute -bottom-6 left-1/2 -translate-x-1/2 whitespace-nowrap text-[10px] font-mono text-emerald-600 font-bold bg-white/80 px-1 rounded shadow-sm border border-emerald-100">
            {object.width.toFixed(1)}m × {object.length.toFixed(1)}m @ {Math.round(object.rotation)}°
          </div>
        </>
      )}
    </div>
  );
};

export default DraggableItem;

import React, { useRef, useState, useEffect } from 'react';
import { StandObject, Boundary, OBJECT_DEFAULTS } from '../types';
import DraggableItem from './DraggableItem';
import { checkCollision, isOutOfBounds } from '../utils/collisions';

interface CanvasProps {
  boundary: Boundary;
  objects: StandObject[];
  selectedId: string | null;
  scale: number;
  onSelect: (id: string | null) => void;
  onUpdate: (id: string, updates: Partial<StandObject>, finalUpdate?: boolean) => void;
}

const Canvas: React.FC<CanvasProps> = ({ boundary, objects, selectedId, scale, onSelect, onUpdate }) => {
  const widthPx = boundary.width * scale;
  const heightPx = boundary.length * scale;

  // 30m site buffer for comprehensive layout planning
  const paddingMeters = 30;
  const paddingPx = paddingMeters * scale;

  return (
    <div 
      id="full-site-canvas"
      className="relative bg-slate-200/50 rounded-lg shadow-inner print:p-0 print:bg-white transition-all"
      style={{ 
        width: widthPx + (paddingPx * 2), 
        height: heightPx + (paddingPx * 2),
        padding: `${paddingPx}px`
      }}
      onClick={() => onSelect(null)}
    >
      <div className="absolute top-4 left-4 text-[10px] font-bold text-slate-400 uppercase tracking-widest print:hidden pointer-events-none">
        Extended Site Ground (30m buffer)
      </div>

      <div 
        className="relative bg-white shadow-2xl border-4 border-slate-800 rounded-sm"
        style={{ width: widthPx, height: heightPx }}
      >
        <div 
          className="absolute inset-0 pointer-events-none opacity-10"
          style={{
            backgroundImage: `linear-gradient(to right, #000 1px, transparent 1px), linear-gradient(to bottom, #000 1px, transparent 1px)`,
            backgroundSize: `${scale}px ${scale}px`
          }}
        />

        <div className="absolute -top-10 left-0 text-xs font-bold text-slate-400 print:text-slate-800">
          Stand Width: {boundary.width}m
        </div>
        <div className="absolute -left-10 top-0 text-xs font-bold text-slate-400 rotate-90 origin-top-left translate-x-3 print:text-slate-800">
          Stand Length: {boundary.length}m
        </div>

        {objects.map((obj) => {
          const colliding = objects.some(other => {
            if (other.id === obj.id) return false;
            const configA = OBJECT_DEFAULTS[obj.type];
            const configB = OBJECT_DEFAULTS[other.type];
            if (configA.ignoreCollision || configB.ignoreCollision) return false;
            return checkCollision(obj, other);
          });

          const outOfBounds = isOutOfBounds(obj, boundary);
          const canBeOutside = obj.type === 'Queue Barrier' || obj.type === 'Fire Extinguisher' || obj.type === 'Entry/Exit Point';

          return (
            <DraggableItem
              key={obj.id}
              object={obj}
              scale={scale}
              boundary={boundary}
              isSelected={selectedId === obj.id}
              hasError={colliding || (outOfBounds && !canBeOutside)}
              onSelect={(e) => {
                e.stopPropagation();
                onSelect(obj.id);
              }}
              onUpdate={(updates, finalUpdate) => onUpdate(obj.id, updates, finalUpdate)}
            />
          );
        })}
      </div>
    </div>
  );
};

export default Canvas;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { VendorInfo, StandObject, ObjectType, OBJECT_DEFAULTS, Boundary } from '../types';
import Sidebar from './Sidebar';
import Canvas from './Canvas';
import Controls from './Controls';
import { toPng } from 'https://esm.sh/html-to-image@1.11.11';

interface DesignerProps {
  vendor: VendorInfo;
  onLogout: () => void;
}

const Designer: React.FC<DesignerProps> = ({ vendor, onLogout }) => {
  const [boundary, setBoundary] = useState<Boundary>({ width: 10, length: 8 });
  const [objects, setObjects] = useState<StandObject[]>([]);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [isBoundarySet, setIsBoundarySet] = useState(false);
  const [isExporting, setIsExporting] = useState(false);

  const [history, setHistory] = useState<StandObject[][]>([]);
  const [redoStack, setRedoStack] = useState<StandObject[][]>([]);
  const [scale, setScale] = useState(40);

  const saveToHistory = useCallback((currentObjects: StandObject[]) => {
    setHistory(prev => [...prev, currentObjects]);
    setRedoStack([]);
  }, []);

  const addObject = useCallback((type: ObjectType) => {
    saveToHistory(objects);
    const defaults = OBJECT_DEFAULTS[type];
    const newObj: StandObject = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      x: boundary.width / 2 - defaults.width / 2,
      y: type === 'Queue Barrier' ? boundary.length + 1 : boundary.length / 2 - defaults.length / 2,
      width: defaults.width,
      length: defaults.length,
      rotation: 0,
      color: defaults.color,
    };
    setObjects(prev => [...prev, newObj]);
    setSelectedId(newObj.id);
  }, [boundary, objects, saveToHistory]);

  const updateObject = (id: string, updates: Partial<StandObject>, finalUpdate = false) => {
    if (finalUpdate) {
      saveToHistory(objects);
    }
    setObjects(prev => prev.map(obj => obj.id === id ? { ...obj, ...updates } : obj));
  };

  const removeObject = (id: string) => {
    saveToHistory(objects);
    setObjects(prev => prev.filter(obj => obj.id !== id));
    if (selectedId === id) setSelectedId(null);
  };

  const undo = useCallback(() => {
    if (history.length > 0) {
      const previous = history[history.length - 1];
      const newHistory = history.slice(0, history.length - 1);
      setRedoStack(prev => [objects, ...prev]);
      setObjects(previous);
      setHistory(newHistory);
    }
  }, [history, objects]);

  const redo = useCallback(() => {
    if (redoStack.length > 0) {
      const next = redoStack[0];
      const newRedoStack = redoStack.slice(1);
      setHistory(prev => [...prev, objects]);
      setObjects(next);
      setRedoStack(newRedoStack);
    }
  }, [redoStack, objects]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.ctrlKey || e.metaKey) && e.key === 'z') {
        if (e.shiftKey) redo();
        else undo();
      } else if ((e.ctrlKey || e.metaKey) && e.key === 'y') {
        redo();
      } else if (e.key === 'Delete' || e.key === 'Backspace') {
        if (selectedId && !['INPUT', 'TEXTAREA'].includes(document.activeElement?.tagName || '')) {
          removeObject(selectedId);
        }
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [undo, redo, selectedId]);

  const resetDesigner = () => {
    if (confirm("Clear your entire sketch?")) {
      saveToHistory(objects);
      setObjects([]);
      setSelectedId(null);
    }
  };

  const exportDesign = async () => {
    const node = document.getElementById('full-site-canvas');
    if (!node) return;

    setIsExporting(true);
    setSelectedId(null); // Clear selection for clean export

    setTimeout(async () => {
      try {
        const dataUrl = await toPng(node, {
          quality: 1,
          pixelRatio: 3, 
          backgroundColor: '#f1f5f9',
          style: {
            padding: '40px',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center'
          }
        });

        const safeTraderName = vendor.traderName.replace(/[^a-z0-9]/gi, '-');
        const safeVendorId = vendor.vendorId.replace(/[^a-z0-9]/gi, '-');
        const link = document.createElement('a');
        link.download = `StandPlan-${safeTraderName}-${safeVendorId}.png`;
        link.href = dataUrl;
        link.click();
      } catch (err) {
        console.error('Export failed:', err);
        alert('Export failed. Please try again.');
      } finally {
        setIsExporting(false);
      }
    }, 150);
  };

  if (!isBoundarySet) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-50">
        <div className="bg-white p-10 rounded-2xl shadow-xl max-w-lg w-full border border-slate-200">
          <h2 className="text-2xl font-bold mb-6 text-slate-800">Set Your Stand Dimensions</h2>
          <p className="text-slate-500 mb-8">Enter the outer boundaries of your pitch in meters.</p>
          <div className="grid grid-cols-2 gap-6 mb-8">
            <div>
              <label className="block text-sm font-semibold text-slate-600 mb-2">Width (m)</label>
              <input
                type="number"
                className="w-full p-4 border rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none"
                value={boundary.width}
                onChange={(e) => setBoundary({ ...boundary, width: parseFloat(e.target.value) || 0 })}
              />
            </div>
            <div>
              <label className="block text-sm font-semibold text-slate-600 mb-2">Length (m)</label>
              <input
                type="number"
                className="w-full p-4 border rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none"
                value={boundary.length}
                onChange={(e) => setBoundary({ ...boundary, length: parseFloat(e.target.value) || 0 })}
              />
            </div>
          </div>
          <button
            onClick={() => setIsBoundarySet(true)}
            className="w-full bg-emerald-600 text-white font-bold py-4 rounded-xl hover:bg-emerald-700 transition shadow-lg"
          >
            Open Workspace
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-screen overflow-hidden bg-slate-100 print:h-auto print:overflow-visible">
      <Sidebar onAddObject={addObject} />

      <main className="flex-1 flex flex-col min-w-0 relative print:bg-white print:p-0">
        <header className="bg-white border-b px-6 py-4 flex items-center justify-between shadow-sm z-30 print:hidden">
          <div className="flex items-center space-x-4">
            <h1 className="text-xl font-bold text-slate-800 truncate max-w-xs">{vendor.traderName}</h1>
            <span className="text-slate-400">|</span>
            <span className="text-sm text-slate-500 font-mono">{vendor.vendorId}</span>
          </div>
          <div className="flex items-center space-x-2">
            <button 
              onClick={undo}
              disabled={history.length === 0}
              className={`p-2 rounded-lg transition ${history.length === 0 ? 'text-slate-200' : 'text-slate-600 hover:bg-slate-100 hover:text-emerald-600'}`}
              title="Undo (Ctrl+Z)"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 10h10a8 8 0 018 8v2M3 10l6 6m-6-6l6-6" /></svg>
            </button>
            <button 
              onClick={redo}
              disabled={redoStack.length === 0}
              className={`p-2 rounded-lg transition ${redoStack.length === 0 ? 'text-slate-200' : 'text-slate-600 hover:bg-slate-100 hover:text-emerald-600'}`}
              title="Redo (Ctrl+Y)"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 10h-10a8 8 0 00-8 8v2m18-8l-6 6m6-6l-6-6" /></svg>
            </button>
            <span className="text-slate-200 mx-2">|</span>
            <button 
              onClick={exportDesign}
              disabled={isExporting}
              className={`px-4 py-2 text-white text-sm font-bold rounded-lg transition flex items-center shadow-sm ${isExporting ? 'bg-slate-400 cursor-not-allowed' : 'bg-slate-800 hover:bg-slate-900'}`}
            >
              <svg className="w-4 h-4 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
              </svg>
              {isExporting ? 'Exporting...' : 'Export (PNG)'}
            </button>
            <span className="text-slate-200 mx-2">|</span>
             <button 
              onClick={resetDesigner}
              className="px-4 py-2 text-sm font-medium text-slate-600 hover:text-red-600 transition"
            >
              Clear
            </button>
            <button 
              onClick={onLogout}
              className="px-4 py-2 text-sm font-medium text-slate-600 hover:text-slate-900 transition"
            >
              Logout
            </button>
          </div>
        </header>

        <div className="flex-1 relative overflow-auto p-12 flex justify-center items-center canvas-container print:p-0 print:overflow-visible">
          <Canvas 
            boundary={boundary} 
            objects={objects} 
            selectedId={selectedId}
            scale={scale}
            onSelect={setSelectedId}
            onUpdate={updateObject}
          />
        </div>

        <Controls 
          selectedObject={objects.find(o => o.id === selectedId) || null}
          onUpdate={updateObject}
          onRemove={removeObject}
          onClose={() => setSelectedId(null)}
        />
      </main>
    </div>
  );
};

export default Designer;

